43	            action: () => dataGrid.Instance.AddGroupColumn( nameColumn.Instance ),
44	            cancellationToken: CancellationToken.None,
45	            creationOptions: TaskCreationOptions.None,
46	            scheduler: new CurrentThreadTaskScheduler() );
47	
48	        await Task.Factory.StartNew(
49	            action: () => dataGrid.Instance.RemoveGroupColumn( nameColumn.Instance ),
50	            cancellationToken: CancellationToken.None,
51	            creationOptions: TaskCreationOptions.None,
52	            scheduler: new CurrentThreadTaskScheduler() );
53	
54	        // validate
55	        comp.WaitForAssertion( () =>
56	        {
57	            groupingChanged.Should().HaveCount( 2 );
58	
59	            groupingChanged[0].ChangeType.Should().Be( DataGridGroupingChangeType.Added );
60	            groupingChanged[0].AddedColumn?.Field.Should().Be( nameof( Employee.Name ) );
61	            groupingChanged[0].RemovedColumn.Should().BeNull();
62	            groupingChanged[0].PreviousGroupedColumns.Should().BeEmpty();
63	            groupingChanged[0].GroupedColumns.Select( x => x.Field ).Should().Equal( nameof( Employee.Name ) );
64	
65	            groupingChanged[1].ChangeType.Should().Be( DataGridGroupingChangeType.Removed );
66	            groupingChanged[1].RemovedColumn?.Field.Should().Be( nameof( Employee.Name ) );
67	            groupingChanged[1].AddedColumn.Should().BeNull();
68	            groupingChanged[1].PreviousGroupedColumns.Select( x => x.Field ).Should().Equal( nameof( Employee.Name ) );
69	            groupingChanged[1].GroupedColumns.Should().BeEmpty();
70	        }, TimeSpan.FromSeconds( 3 ) );
71	    }
