1039	    /// If IsGroupable feature is active. Groups the data for Display.
1040	    /// </summary>
1041	    private void GroupDisplayData()
1042	    {
1043	        if ( !IsGroupEnabled )
1044	        {
1045	            groupedData = null;
1046	            return;
1047	        }
1048	
1049	        if ( GroupBy is null )
1050	        {
1051	            var firstGroupableColumn = groupableColumns[0];
1052	
1053	            var query = DisplayData
1054	                .GroupBy( x => firstGroupableColumn.GetGroupByFunc().Invoke( x ) )
1055	                .Select( x => new GroupContext<TItem>( x, firstGroupableColumn.GroupTemplate ) );
1056	
1057	            var newGroupedData = ( firstGroupableColumn.CurrentSortDirection switch
1058	            {
1059	                SortDirection.Ascending => query.OrderBy( context => context.Key ),
1060	                SortDirection.Descending => query.OrderByDescending( context => context.Key ),
1061	                _ => query
1062	            } )
1063	            .ToList();
1064	
1065	            GroupSyncState( groupedData, newGroupedData );
1066	            groupedData = newGroupedData;
1067	        }
1068	        else
1069	        {
1070	            var newGroupedData = DisplayData
1071	                .GroupBy( x => GroupBy.Invoke( x ) )
1072	                .Select( x => new GroupContext<TItem>( x ) )
1073	                .OrderBy( x => x.Key )
1074	                .ToList();
1075	
1076	            GroupSyncState( groupedData, newGroupedData );
1077	            groupedData = newGroupedData;
1078	        }
