1107	    /// <param name="oldGroupedData"></param>
1108	    /// <param name="newGroupedData"></param>
1109	    private void RecursiveGroup( int iteration, List<GroupContext<TItem>> oldGroupedData, List<GroupContext<TItem>> newGroupedData )
1110	    {
1111	        if ( newGroupedData.IsNullOrEmpty() )
1112	            return;
1113	
1114	        foreach ( var group in newGroupedData )
1115	        {
1116	            var oldGroup = GroupSyncState( oldGroupedData, group );
1117	
1118	            var nextGroupableColumn = groupableColumns?.ElementAtOrDefault( iteration );
