    /// <summary>
    /// Loads the state of the DataGrid.
    /// </summary>
    /// <param name="dataGridState">The state to be loaded, If null no action is taken.</param>
    /// <returns></returns>
    public async Task LoadState( DataGridState<TItem> dataGridState )
    {
        if ( dataGridState is null )
        {
            return;
        }

        // Prevent re-entrancy and suppress event storms during state application
        if ( applyingState )
        {
            return;
        }

        applyingState = true;

        try
        {
            // Keep the overlay on while we batch changes
            SetLoading( true );

            PageSize = dataGridState.PageSize;
            Page = dataGridState.Page;

            // Column displaying + order
            if ( !dataGridState.ColumnDisplayingStates.IsNullOrEmpty() )
            {
                foreach ( var displayingState in dataGridState.ColumnDisplayingStates )
                {
                    var column = Columns?.Find( x => x.Field == displayingState.FieldName );

                    if ( column is not null )
                    {
                        await column.SetDisplaying( displayingState.Displaying );
                        await column.SetDisplayOrder( displayingState.DisplayOrder );
                    }
                }
            }
            else
            {
                await ResetDisplaying();
                await ResetDisplayOrder();
            }

            // Sorting
            if ( dataGridState.ColumnSortStates.IsNullOrEmpty() )
            {
                await ResetSorting();
            }
            else
            {
                // Keep existing behavior; apply sequentially
                await ResetSorting();

                foreach ( var sortState in dataGridState.ColumnSortStates )
                {
                    await Sort( sortState.FieldName, sortState.SortDirection );
                }
            }

            // Filtering
            if ( dataGridState.ColumnFilterStates.IsNullOrEmpty() )
            {
                ResetFiltering();
            }
            else
            {
                foreach ( var filterState in dataGridState.ColumnFilterStates )
                {
                    var column = Columns?.Find( x => x.Field == filterState.FieldName );
                    if ( column is not null )
                    {
                        if ( filterState.HasFilterMethod )
                        {
                            column.SetFilterMethod( filterState.FilterMethod );
                        }

                        column.Filter.SearchValue = DataGridFilterUtils.CoerceSearchValue( column, filterState.SearchValue );
                    }
                }

                FilterData();
            }

            // Grouping
            var previousSuppressGroupingChangedNotifications = suppressGroupingChangedNotifications;
            suppressGroupingChangedNotifications = true;

            try
            {
                if ( GroupBy is null )
                {
                    ResetGrouping();

                    if ( !dataGridState.ColumnGroupingStates.IsNullOrEmpty() )
                    {
                        foreach ( var groupingState in dataGridState.ColumnGroupingStates )
                        {
                            var column = Columns?.Find( x => x.Field == groupingState.FieldName );

                            if ( column is not null )
                            {
                                AddGroupColumn( column, true );
                            }
                        }
                    }
                }
            }
            finally
            {
                suppressGroupingChangedNotifications = previousSuppressGroupingChangedNotifications;
            }

            // Selection (defer event callbacks until after ReloadInternal)
            SelectedRow = dataGridState.SelectedRow;
            SelectedRows = dataGridState.SelectedRows;

            if ( dataGridState.EditState == DataGridEditState.None )
            {
                await Cancel();
            }
            else if ( dataGridState.EditState == DataGridEditState.New )
            {
                await New();
            }
            else if ( dataGridState.EditState == DataGridEditState.Edit && dataGridState.EditItem is not null )
            {
                await Edit( dataGridState.EditItem );
            }

            await ReloadInternal();

            await SelectedRowChanged.InvokeAsync( dataGridState.SelectedRow );
            await SelectedRowsChanged.InvokeAsync( dataGridState.SelectedRows );
        }
        finally
        {
            SetLoading( false );
            applyingState = false;
            await InvokeAsync( StateHasChanged );
        }
    }

    /// <summary>
    /// Gets the current state of the DataGrid.
    /// </summary>
    /// <returns></returns>
    public Task<DataGridState<TItem>> GetState()
    {
        var dataGridState = new DataGridState<TItem>()
        {
            Page = Page,
            PageSize = PageSize,
            EditState = EditState,
            EditItem = editState == DataGridEditState.None ? default : editItem,
            SelectedRow = SelectedRow,
            SelectedRows = SelectedRows
        };

        if ( !SortByColumns.IsNullOrEmpty() )
        {
            dataGridState.ColumnSortStates = SortByColumns.Select( x => new DataGridColumnSortState<TItem>( x.Field, x.CurrentSortDirection ) ).ToList();
        }

        if ( Columns.Exists( x => x.Filter?.SearchValue != null ) )
        {
            dataGridState.ColumnFilterStates = Columns.Where( x => x.Filter?.SearchValue is not null ).Select( x => new DataGridColumnFilterState<TItem>( x.Field, x.Filter.SearchValue )
            {
                FilterMethod = x.GetFilterMethod() ?? x.GetDataGridFilterMethodAsColumn(),
            } ).ToList();
        }

        dataGridState.ColumnDisplayingStates = Columns.Where( x => x.IsRegularColumn ).Select( x => new DataGridColumnDisplayingState<TItem>( x.Field, x.Displaying, x.GetDisplayOrder() ) ).ToList();

        if ( GroupBy is null && !groupableColumns.IsNullOrEmpty() )
        {
            dataGridState.ColumnGroupingStates = groupableColumns.Select( x => new DataGridColumnGroupingState<TItem>( x.Field ) ).ToList();
        }

        return Task.FromResult( dataGridState );
    }

